// ── HELPERS ───────────────────────────────────────────────────

/** Returns a sticker object by id, or null */
window.getStickerById = function (id) {
    return window.STICKERS.find(s => s.id === id) || null;
};

/** Returns all stickers for a given team name */
window.getStickersByTeam = function (team) {
    return window.STICKERS.filter(s => s.team === team);
};

/** Returns all unique team names present in the catalog */
window.getTeamNames = function () {
    return [...new Set(window.STICKERS.map(s => s.team))];
};

/** Total stickers in the album (unique slots to fill) */
window.TOTAL_STICKERS = window.STICKERS.length;
